std::string to_cli_key(std::string_view key) {
  std::string cli_key;
  cli_key.reserve(key.size());
  for (const char c : key) {
    cli_key.push_back(c == '_' ? '-' : c);
  }
  return cli_key;
}

std::string to_cli_option_name(std::string_view key) {
  if (key.size() == 1) {
    return "-" + std::string(key);
  }
  return "--" + to_cli_key(key);
}

