std::optional<std::filesystem::path> parse_config_path(int argc, char **argv) {
  std::string config_path;
  CLI::App app{"gpjson driver config pre-parser"};
  app.allow_extras();
  app.set_help_flag("", "");
  app.add_option("-c,--config", config_path, "TOML config file path");
  app.parse(argc, argv);
  if (config_path.empty()) {
    return std::nullopt;
  }
  return std::filesystem::path(config_path);
}

